// 组装飞书消息 + 计算飞书加签 (HMAC-SHA256)
const crypto = require('crypto');
const v = $('变量提取').first().json;
const r = items[0].json;
const actionEmoji = { '取扱中止': '🚫', '継続': '✅', '代替品調査': '🔍' }[v.action] || '⚠️';
const linkageNote = r.linkage_applied ? '· item_master.rank → 停売 ✅' : '';
const msg = `${actionEmoji} 改廃確認 [JAN ${v.jan}] · ${v.action}\n${linkageNote}\nupdated_alerts=${r.updated_alerts} · operator=${v.operator}\nrun_id=${v.run_id}`;
// 飞书自定义机器人加签: HMAC-SHA256(timestamp+"\n"+secret AS KEY, '') → base64
const ts = Math.floor(Date.now() / 1000);
const secret = $env.LARK_EXPORT_BIZ_SIGN_SECRET || $env.LARK_BOT_SIGN_SECRET || '';
const stringToSign = `${ts}\n${secret}`;
const sign = crypto.createHmac('sha256', stringToSign).update('').digest('base64');
return [{ json: { msg, timestamp: String(ts), sign, run_id: v.run_id, updated_alerts: r.updated_alerts, linkage_applied: r.linkage_applied, action: v.action } }];
